1	import { useRef, useState, useEffect } from 'react';
2	import gsap from 'gsap';
3	import { useGSAP } from '@gsap/react';
4	import { INTENTS } from '../data/ecosystem.js';
5	import { prefersReduced } from '../lib/anim.js';
6	import { entityMeta } from '../lib/api.js';
7	import './matches.css';
8	
9	const SKELETON_ROWS = [0, 1, 2];
10	
11	// Multi-select checkbox popover (shadcn-style pattern, styled with our tokens).
12	function SectorSelect({ options, selected, onChange }) {
13	  const [open, setOpen] = useState(false);
14	  const wrapRef = useRef(null);
15	
16	  useEffect(() => {
17	    if (!open) return;
18	    const onDown = (e) => {
19	      if (wrapRef.current && !wrapRef.current.contains(e.target)) setOpen(false);
20	    };
21	    const onKey = (e) => {
22	      if (e.key === 'Escape') setOpen(false);
23	    };
24	    document.addEventListener('mousedown', onDown);
25	    document.addEventListener('keydown', onKey);
26	    return () => {
27	      document.removeEventListener('mousedown', onDown);
28	      document.removeEventListener('keydown', onKey);
29	    };
30	  }, [open]);
31	
32	  const toggle = (s) =>
33	    onChange(selected.includes(s) ? selected.filter((x) => x !== s) : [...selected, s]);
34	  const label =
35	    selected.length === 0 ? 'All sectors' : selected.length === 1 ? selected[0] : selected.length + ' sectors';
36	
37	  return (
38	    <div className="vn-sector-select" ref={wrapRef}>
39	      <button
40	        type="button"
41	        className={'vn-match-filter-chip vn-sector-trigger' + (selected.length ? ' active' : '')}
42	        aria-haspopup="true"
43	        aria-expanded={open}
44	        onClick={() => setOpen(!open)}
45	      >
46	        {label}
47	        <span className="vn-sector-caret" aria-hidden="true">▾</span>
48	      </button>
49	      {open && (
50	        <div className="vn-sector-menu">
51	          {options.map((s) => (
52	            <label className="vn-sector-item" key={s}>
53	              <input type="checkbox" checked={selected.includes(s)} onChange={() => toggle(s)} />
54	              <span>{s}</span>
55	            </label>
56	          ))}
57	          {selected.length > 0 && (
58	            <button type="button" className="vn-sector-clear" onClick={() => onChange([])}>
59	              Clear selection
60	            </button>
61	          )}
62	        </div>
63	      )}
64	    </div>
65	  );
66	}
67	
68	export default function Matches({ role, profileName, intent, live, matchStatus, matchError, onRetry, onIntent, topK, onTopK, filter, onFilter, typeOptions, sectorOptions, items, total, title, sub, onOpen, onBackToForm }) {
69	  const rootRef = useRef(null);
70	
71	  useGSAP(() => {
72	    if (prefersReduced() || !rootRef.current) return;
73	    const cards = rootRef.current.querySelectorAll('.vn-match-card');
74	    if (!cards.length) return;
75	    gsap.from(cards, { y: 14, autoAlpha: 0, duration: 0.45, ease: 'power2.out', stagger: 0.05, clearProps: 'all' });
76	  }, { scope: rootRef, dependencies: [intent, topK, matchStatus, filter] });
77	
78	  const ready = live && matchStatus === 'ready';
79	  const filtering = filter.type !== 'all' || filter.sectors.length > 0;
80	  const clearFilters = () => onFilter({ type: 'all', sectors: [] });
81	
82	  const openCard = (candidate, rank) => onOpen({ candidate, rank });
83	
84	  return (
85	    <div className="vn-match-root" ref={rootRef}>
86	      <a className="link" onClick={onBackToForm}>← Edit profile</a>
87	      <div className="eyebrow vn-match-eyebrow">Matches · reasoning-ranked</div>
88	      <h1 className="serif-h1 vn-match-h1">{title}</h1>
89	      <p className="lede vn-match-lede">{sub} Scored 0 to 100 so you don't spend time searching.</p>
90	
91	      <div className="vn-match-tabs">
92	        {INTENTS.map((it) => (
93	          <button
94	            key={it.id}
95	            type="button"
96	            className={'vn-match-tab' + (it.id === intent ? ' active' : '')}
97	            onClick={() => onIntent(it.id)}
98	          >
99	            {it.id === 'investors' && role === 'investor' ? 'Startup' : it.tab}
100	          </button>
101	        ))}
102	      </div>
103	
104	      {ready && (typeOptions.length > 1 || sectorOptions.length > 1) && (
105	        <div className="vn-match-filters">
106	          {typeOptions.length > 1 && (
107	            <div className="vn-match-filter-group">
108	              <span className="vn-match-filter-label">Type</span>
109	              {['all', ...typeOptions].map((t) => (
110	                <button
111	                  key={t}
112	                  type="button"
113	                  className={'vn-match-filter-chip' + (filter.type === t ? ' active' : '')}
114	                  onClick={() => onFilter({ ...filter, type: t })}
115	                >
116	                  {t !== 'all' && <span className="dot" style={{ background: entityMeta(t).dot }}></span>}
117	                  {t === 'all' ? 'All' : entityMeta(t).label}
118	                </button>
119	              ))}
120	            </div>
121	          )}
122	          {sectorOptions.length > 1 && (
123	            <div className="vn-match-filter-group">
124	              <span className="vn-match-filter-label">Sector</span>
125	              <SectorSelect
126	                options={sectorOptions}
127	                selected={filter.sectors}
128	                onChange={(sectors) => onFilter({ ...filter, sectors })}
129	              />
130	            </div>
131	          )}
132	        </div>
133	      )}
134	
135	      {ready && items.length > 0 && (
136	        <div className="vn-match-count-row">
137	          <span className="vn-match-count">Showing top {items.length} of {total}</span>
138	          <div className="seg vn-match-seg">
139	            <button type="button" className={'seg-btn' + (topK === 5 ? ' active' : '')} onClick={() => onTopK(5)}>Top 5</button>
140	            <button type="button" className={'seg-btn' + (topK === 10 ? ' active' : '')} onClick={() => onTopK(10)}>Top 10</button>
141	            <button type="button" className={'seg-btn' + (topK >= total ? ' active' : '')} onClick={() => onTopK(999)}>All</button>
142	          </div>
143	        </div>
144	      )}
145	
146	      {!live && (
147	        <div className="vn-match-state">
148	          <p className="vn-match-state-text">This match type isn't connected to a backend service yet. Only {role === 'investor' ? 'startup' : 'investor'} matching is live today.</p>
149	        </div>
150	      )}
151	
152	      {live && matchStatus === 'loading' && (
153	        <div className="vn-match-loading" aria-busy="true" aria-live="polite">
154	          <span className="vn-match-loading-label">Ranking matches from your profile…</span>
155	          <div className="vn-match-skeleton" aria-hidden="true">
156	            {SKELETON_ROWS.map((i) => (
157	              <div className="vn-match-skel-card" key={i}>
158	                <span className="vn-skel vn-skel-rank" />
159	                <span className="vn-skel vn-skel-score" />
160	                <div className="vn-match-skel-body">
161	                  <span className="vn-skel vn-skel-line vn-skel-type" />
162	                  <span className="vn-skel vn-skel-line vn-skel-name" />
163	                  <span className="vn-skel vn-skel-line vn-skel-rationale" />
164	                </div>
165	              </div>
166	            ))}
167	          </div>
